create table dirkspzm32.pps_plan_auftrag (
    sid                  varchar2(2 char) not null enable,
    firma_nr             number(6, 0) not null enable,
    plan_auf_id          number(*, 0) not null enable,
    plan_auf_id_ext      number(*, 0),
    artikel_id           number(*, 0) not null enable,
    zeichnung            varchar2(255 char),
    zeichnung_index      varchar2(10 char),
    menge                number(*, 3) not null enable,
    status               varchar2(10 char) default 'N' not null enable,
    erz_datum            date not null enable,
    erz_login_id         number(*, 0),
    aend_datum           date,
    aend_login_id        number(*, 0),
    erzeuger             varchar2(10 char) default 'ISI' not null enable,
    prod_params          varchar2(4000 char),
    kunden_nr            varchar2(20 char),
    kd_art_nr            varchar2(30 char),
    kd_best_nr           varchar2(30 char),
    kd_best_pos          varchar2(5 char),
    kd_best_text1        varchar2(255 char),
    kd_best_text2        varchar2(255 char),
    kd_best_text3        varchar2(255 char),
    termin_ende          date,
    termin_soll_start    date,
    arb_plan_id          number(*, 0),
    unique_hash          varchar2(200 char),
    soll_betriebsart     varchar2(10 char),
    serie_id             number(*, 0),
    serie_auto_inc       varchar2(1 char) default 'F',
    fa_gruppe            number(*, 5),
    created_date         date default sysdate not null enable,
    created_login_id     number(*, 0) default - 1 not null enable,
    last_change_date     date,
    last_change_login_id number(*, 0)
);

alter table dirkspzm32.pps_plan_auftrag
    add constraint pk_pps_plan_auftrag
        primary key ( plan_auf_id,
                      firma_nr,
                      sid )
            using index enable;


